var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"말해.","JPN":"言いなさい。","ENG":"Tell me.","TWN":"說吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"자크는 어디에 숨어있지?","JPN":"ジャックはどこに隠れてるの？","ENG":"Where is Jacques hiding?","TWN":"札克躲在哪裡？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"큭큭... 숨긴 누가 숨어. 우리 혁명군이 너희 같은 겁쟁이인 줄 아냐?","JPN":"ククッ……隠れる必要がどこにある？　我が革命軍はてめえらみたいな弱虫じゃないんだぜ？","ENG":"Heh heh... Hiding? Who said anything about hiding? Do you think our Resistance is full of cowards like you?","TWN":"呵呵……誰躲起來了啊？你以為我們革命軍會怕你們這種懦夫嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"보안국의 개 주제에 감히 그 이름을 함부로 담지 마시지.","JPN":"保安局の犬が、軽々しくあの人の名を呼ばないでほしいね。","ENG":"Watch your mouth. A dog of the National Security shouldn't dare speak that name so lightly.","TWN":"你這安全局的走狗，竟敢隨便提起那個名字？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"뭐?","JPN":"何だよ？","ENG":"What?","TWN":"怎樣？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"순혈지식 연대의 테오도르 팔머.","JPN":"純血知識連帯のテオドール・パルマー。","ENG":"Theodor Palmer of the Pure Blood Regiment.","TWN":"純血知識年代的西奧多．帕默。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"건국기념전당 폭발 사건에, 너 역시 가담했었지.","JPN":"建国記念館の爆発事件に加担していたよね。","ENG":"You were involved in the bombing at the National Foundation Hall as well.","TWN":"你也參與了建國紀念堂爆炸案吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"건국기념전당?","JPN":"建国記念館？","ENG":"The National Foundation Hall?","TWN":"建國紀念堂？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"그러고 보니 그 얼굴... 설마 그 여자의?","JPN":"その顔……まさか、あの女の？","ENG":"Now that I look at you... That face... Don't tell me you're that woman's–?","TWN":"這麼說來你那張臉……難道是那女人的女兒？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"판단이 빠르네. 그럼 내가 널 어떻게 할 지도 알고 있으려나?","JPN":"勘が鋭いじゃない。じゃあ、私がどうするつもりかも分かる？","ENG":"Quick on the uptake. Then you must know what I'm going to do to you, right?","TWN":"判斷還真快呢。那你應該也知道我會怎麼對付你吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"어처구니가 없군.","JPN":"ふざけやがって。","ENG":"How absurd.","TWN":"真荒謬。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"날 납치한다고 뭐가 해결되는데?","JPN":"俺を拉致したところで何が解決するっていうんだ？","ENG":"What does kidnapping me solve?","TWN":"綁架我能解決什麼問題？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"<color=#ffd34c>루이제 슈나이더는 자신의 안전을 위해 반군들과 협력하고 있었다.</color>","JPN":"<color=#ffd34c>ルイーゼ・シュナイダーは自分の身の安全のため、反乱軍に協力していた。</color>","ENG":"<color=#ffd34c>Louise Schneider had been cooperating with the rebels for the sake of her own safety.</color>","TWN":"<color=#ffd34c>露易絲．修奈德為了自身安全，曾與反抗軍合作。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"군중의 질책을 피하려고 던진 네 거짓 선동이 한 사람의 인생을 통째로 망가트렸어.","JPN":"群衆から非難されないためにばら撒いた偽の扇動で、一人の人の人生すべてを滅茶苦茶にした。","ENG":"The lie you spread to escape the public's condemnation ruined an innocent person's entire life.","TWN":"你為了躲避群眾責難而散布的謊言，毀了一個人的人生。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"...그건 필요한 희생이었다.","JPN":"……その犠牲は必要なものだったんだ。","ENG":"...It was a necessary sacrifice.","TWN":"……那是必要的犧牲。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"그 여자 하나 때문에 민중의 지지를 받는 혁명군 전체의 이미지가 실추되어선 안 됐으니까.","JPN":"あの女一人のために、民衆から支持を集めている革命軍全体のイメージを汚すわけにはいかなかったからな。","ENG":"The entire Resistance couldn't afford to lose the people's support because of one woman.","TWN":"整個革命軍的形象不能因為那個女人而失去民眾的支持。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"네가 정부에 충성하는 개라면 작은 희생이 필요하단 것쯤은 누구보다 잘 이해하고 있겠지.","JPN":"お前が政府に忠誠を誓っている犬なら、小さな犠牲が必要なことくらい誰よりも理解してるはずだろう？","ENG":"If you're the government's loyal hound, you should understand better than anyone that small sacrifices are sometimes necessary.","TWN":"如果你是忠於政府的走狗，那麼你一定比誰都明白，小小的犧牲是必須的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"너흰 스스로를 애국자라 생각하지.","JPN":"君たちは自らを愛国者だと思ってるんだろうね。","ENG":"You think of yourselves as patriots.","TWN":"你們自詡為愛國者吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"자신들이 벌인 짓 때문에 무고한 사람 수백이 휘말려도, 그걸 대의라는 숭고한 사상으로 포장하면서 말이야.","JPN":"自分たちが起こした事件のせいで何の罪もない多くの人が巻き込まれても、それを大儀という崇高な思想で美化してさ。","ENG":"Even when hundreds of innocent people are dragged into the consequences of what you've done, you dress it up as some noble cause.","TWN":"即使自己的所作所為傷害了數百個無辜的人，依舊能用崇高的理念包裝這一切。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"끄아악!!","JPN":"くはあっ！！","ENG":"Aaaagh!!","TWN":"啊啊啊！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"자, 잠깐...!","JPN":"ま、待て……！","ENG":"W-wait...!","TWN":"等、等一下……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"날 죽이는 건 별 의미가 없어. 너도 그 정도는 알잖아. 자크에 대한 정보가 필요한 거지?","JPN":"俺を殺しても意味がない。お前もそれくらいは分かってるはずだ。ジャックの情報が必要なんだろう？","ENG":"You know that killing me won't accomplish much. You're after information on Jacques, right?","TWN":"你不也知道殺了我沒什麼意義嗎？你需要的是札克的情報，對吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"대장을 노리는 거잖아! 안 그래? 결국 그날 일을 주도했던 건 지휘관이니까!","JPN":"隊長を狙ってるんだろう！　違うか？　結局あの日の事件を主導したのは指揮官だからな！","ENG":"You're aiming for him! Aren't you? He was the one who orchestrated what happened that day!","TWN":"你的目標不是隊長嗎？對吧？畢竟是他主導那天的事！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"걱정 마. 모두 다 대가를 치르게 될 거야.","JPN":"安心して。全員に償いはさせるから。","ENG":"Don't worry. Everyone will pay the price.","TWN":"別擔心，所有人都會付出代價。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"네가 먼저일 뿐이지.","JPN":"ただ、君が最初ってだけ。","ENG":"You're just first.","TWN":"只是從你開始而已。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그럼에도, 우리에겐 대의라는 명분이 필요해.","JPN":"だとしても、私たちには大儀という口実がいる。","ENG":"Even so, we still need a cause to justify ourselves.","TWN":"但即便如此，我們仍需要一個名目。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"그래야만, 죄의식이라는 타고난 본능으로부터 우리 스스로를 지킬 수 있으니까.","JPN":"でないと、罪の意識という持って生まれた本能から自分自身を守ることができないから。","ENG":"Otherwise, we can't protect ourselves from the instinctive guilt we're born with.","TWN":"這樣才能保護自己不被天生的罪惡感吞噬。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRISON_NPC_HARMONY_NULL","text":{"KOREA":"살려주게... 제단의 위치부터 그 여자가 사는 곳까지, 전부 말해줬잖나.","JPN":"助けてくれ……祭壇の位置からあの女が住んでる場所まで、全部話しただろう？","ENG":"Have mercy... I told you everything. The location of the altar, even where that woman lives.","TWN":"饒了我吧……我已經把祭壇的位置、那個女人住的地方都告訴你了。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRISON_NPC_HARMONY_NULL","text":{"KOREA":"대체... 나한테 뭘 원하는 건가?","JPN":"いったい……これ以上何を聞き出そうというのだ？","ENG":"What... exactly do you want from me?","TWN":"你到底……想從我這裡得到什麼？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"겔베다스. 당신은 아나필리스의 신앙심 깊은 교인이자, 누구보다 요정의 목소리를 충실히 이행하는 자였죠.","JPN":"ゲルベダス。あなたはアナピリスの敬虔な信徒であり、誰よりも妖精の声に忠実でした。","ENG":"Gelvedas. You were a devout follower of Anapilis, a man who carried out the will of the fairies more faithfully than anyone else.","TWN":"格爾貝達斯。你是阿納菲莉絲虔誠的信徒，比任何人都忠實於精靈的聲音。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ONLY_FIERCE_HARMONY_SOPRANO_SKILL_1"},{"id":"L47_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"눈물을 멈추고 고개를 드세요. 오늘 이곳은 당신을 심판하기 위한 자리가 아닙니다.","JPN":"もう泣かないで、顔を上げてください。今日のこの場はあなたを審判するために設けたのではありません。","ENG":"Stop your tears and lift your head. Today is not a place to judge you.","TWN":"抬起頭，停止哭泣。今天這裡不是審判你的場合。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"한 가지의 진실만을 믿어온 당신에게 우리가 믿는 신앙을 들려주고 싶을 뿐.","JPN":"ただ一つの真実のみを信じてきたあなたに、私たちの信仰をお伝えしたいだけなのです。","ENG":"We simply wish to share with you the faith that we believe in.","TWN":"我們只是想讓只相信唯一真理的你，聆聽我們的信仰。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRISON_NPC_HARMONY_NULL","text":{"KOREA":"아아... 엘리시움 필하모닉.","JPN":"ああ……エリシウムフィルハーモニー。","ENG":"Aah... Elysium Philharmonic.","TWN":"啊啊……愛樂組織。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PRISON_NPC_HARMONY_NULL","text":{"KOREA":"사람의 인격을 물건처럼 다루는 자네 같은 광인들에게 신앙을 논할 자격은 없다네.","JPN":"人の人格を物のように扱う君らのような狂人に信仰を論ずる資格などあるまい。","ENG":"Madmen like you, who treat human personalities like objects, have no right to speak of faith.","TWN":"你們這種把人格當作物品的瘋子，根本不配談信仰。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"절망 속에서 잡을 수 있는 한 줄기 빛. 신앙이란 건 그런 거죠.","JPN":"絶望の中で掴むことのできる一筋の光。信仰とはそのようなものです。","ENG":"A ray of light one can grasp in the depths of despair. That is what faith is.","TWN":"信仰，是在絕望中抓住的一縷光。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"당신들과 우리의 목적은 그리 다르지 않습니다.","JPN":"あなたたちと私たちの目的に大きな違いはありません。","ENG":"Your goal and ours are not so different.","TWN":"你們的目的跟我們沒有太大不同。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRISON_NPC_HARMONY_NULL","text":{"KOREA":"자네들이 하는 짓은...! 희생자 말곤 아무 것도 남기지 못했어!","JPN":"君たちのやってきたことは……！　犠牲者を残すだけだった！","ENG":"What you're doing...! Leaves nothing behind but victims!","TWN":"你們所做的……！除了犧牲者以外什麼也沒留下！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"멘탈 프린팅은 결국 세상을 구원할 겁니다.","JPN":"メンタル・プリンティングは世界を救うでしょう。","ENG":"Mental Printing will ultimately save this world.","TWN":"智力複印，終將拯救世界。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"당신들이 저질러온 살인이 세상을 위한 것이듯 말이죠.","JPN":"あなたたちの犯してきた殺人が世界を救うためであったように。","ENG":"Just as the killings you have committed were meant for the sake of the world.","TWN":"就像你們展開的殺戮行為，是為了這個世界一樣。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRISON_NPC_HARMONY_NULL","text":{"KOREA":"그들은 운명이 택한 제물이라네.","JPN":"彼らは運命が選んだ生贄だ。","ENG":"They were sacrifices chosen by fate.","TWN":"他們是命運選中的祭品。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRISON_NPC_HARMONY_NULL","text":{"KOREA":"인간인 우리가 할 수 있는 건, 그저 그 선택을 따르는 것 뿐.","JPN":"人間である我々にできるのは、ただその選択に従うのみ。","ENG":"All we humans can do is follow that choice.","TWN":"身為人類，我們能做的只是遵循這個選擇而已。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRISON_NPC_HARMONY_NULL","text":{"KOREA":"세계를 존속하기 위한 작은 희생이지. 우릴 이교도라 부르는 자넨 결코 이해 못 할 거야.","JPN":"世界を存続させるための小さな犠牲なのだ。我々を異教徒と呼んでいる君には決して理解できないだろうがね。","ENG":"A small sacrifice to ensure the world's survival. Someone like you, who calls us heretics, will never understand.","TWN":"為了維持世界的延續，這只是小小的犧牲罷了。你們這些稱我們為異教徒的人永遠不會懂。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"아뇨. 이해합니다.","JPN":"いいえ。分かります。","ENG":"No. I do understand.","TWN":"不，我能理解。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"마왕의 탄생과 함께 세상이 종말을 맞게 될 거란 예언은 엘리시온에도 익히 알려져 있으니까요.","JPN":"魔王の誕生とともに世界が終わりを迎えるという予言は、エリシオンでも広く知られていますから。","ENG":"After all, the prophecy that the world will meet its end with the birth of the Demon Lord is well known in Elysion as well.","TWN":"魔王誕生伴隨著世界將迎來末日的預言，在艾利森也廣為人知。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"당신들은 그 예언이 실현됨을 막기 위해, 마왕의 탄생과 엮인 사람들을 죽였을 뿐이죠.","JPN":"あなたたちはその予言が実現されるのを阻止するため、魔王の誕生と関係のある人たちを殺しただけです。","ENG":"You simply killed those connected to the birth of the Demon Lord in order to prevent that prophecy from coming true.","TWN":"你們只是為了阻止這個預言的實現，殺死與魔王誕生有關的人而已。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"운명이 택한 제물... 이라는 명분으로요.","JPN":"運命が選んだ生贄……という口実で。","ENG":"Under the pretext that they were sacrifices chosen by fate.","TWN":"以命運選中的祭品……為名義。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRISON_NPC_HARMONY_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그리고 그건 당신도 마찬가지에요.","JPN":"そして、それはあなたにも当てはまります。","ENG":"And the same goes for you.","TWN":"而你也一樣。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"오늘 당신이 이 자리에 있는 건...","JPN":"今日あなたがここにいるのは……","ENG":"You, too, are nothing more than a sacrifice chosen by fate.","TWN":"今天你在這裡，"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"...우리의 명분을 위한 운명입니다.","JPN":"……私たちの口実のために選ばれた運命だからです。","ENG":"The reason you are here today...","TWN":"……是為了我們的名義與命運。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"우리는 본질적으로 다르지 않아요.","JPN":"私たちは本質的に同じなのです。","ENG":"At our essence, we are no different.","TWN":"我們本質上沒什麼不同。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"...레아 슈나이더.","JPN":"……レア・シュナイダー。","ENG":"...Leah Schneider.","TWN":"……蕾亞．修奈德。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"여긴...?","JPN":"ここは……？","ENG":"Where am I...?","TWN":"這裡是……？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"아, 눈 떴네.","JPN":"あ、起きた。","ENG":"Ah, you're awake.","TWN":"啊，你醒了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"배고파? 딸기 먹을래요? 이거 엄청 맛있어.","JPN":"お腹空いた？　イチゴ食べる？　これ、すごく美味しいよ。","ENG":"Are you hungry? Want a strawberry? These are really delicious.","TWN":"你餓了嗎？想吃草莓嗎？這個超好吃。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"꼬마...? 왜 이런 곳에 꼬마가...","JPN":"子ども……？　どうしてこんなところに子どもが……","ENG":"A kid...? Why is there a kid in a place like this...?","TWN":"小孩子……？為什麼會在這種地方……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"꼬마는 그냥 있는 거야. 여기가 어디든.","JPN":"子どもはいるんだよ。ここがどこでも。","ENG":"Kids just exist. No matter where they are.","TWN":"無論這裡是哪裡，小孩子只是存在在這裡而已。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"여기가 어딘지, 넌 알고 있어?","JPN":"ここがどこか、君は知ってるの？","ENG":"Do you know where you are?","TWN":"你知道這裡是哪嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"내가 어디에 있는지는 작은 문제야. 거기에 있는 내가 누구인지만 알면 돼.","JPN":"自分がどこにいるのかは小さな問題だ。そこにいる自分が誰なのか分かればいい。","ENG":"Where I am is a small matter. As long as I know who I am there.","TWN":"我在哪裡不重要，只要知道站在那裡的是誰就夠了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"...라고 벌레 아저씨가 그랬어요.","JPN":"……って、デレおじさんが言ってた。","ENG":"...That's what Mr. Belly said.","TWN":"……蟲子大叔是這麼說的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 누구인지?","JPN":"自分が誰なのか？","ENG":"Who I am?","TWN":"我是誰？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"난, 레아 슈나이더...","JPN":"私は、レア・シュナイダー……","ENG":"I'm Leah Schneider...","TWN":"我叫蕾亞．修奈德……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그리고...","JPN":"そして……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...네퀴티아.","JPN":"……ネキティア。","ENG":"...Nequitia.","TWN":"……莉奎蒂亞。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"이름이 두 개? 그런 거 처음 들어봤는데.","JPN":"名前が2つ？　そんなの初めて。","ENG":"You have two names? I've never heard of anything like that before.","TWN":"你有兩個名字？我還是第一次聽到這種事。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"그럼 두 명이니까, 딸기 두 개 줄게요.","JPN":"じゃあ二人だから、イチゴ2個あげるね。","ENG":"Then since there are two of you, here are two strawberries.","TWN":"那我就給你兩個草莓吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아... 고마워.","JPN":"あ……ありがとう。","ENG":"Ah... thanks.","TWN":"啊……謝謝。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 알던 딸기랑 모양은 좀 다른데... 엄청 달콤해. 딸기철인가?","JPN":"私の知ってるイチゴとはちょっと違う形をしてるけど……すごく甘い。旬なのかな？","ENG":"These look a little different from the strawberries I know... But they're incredibly sweet. Is it strawberry season?","TWN":"這草莓和我以前吃的形狀不太一樣……超級甜。現在是草莓季嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그러고 보니, 딸기가 나는 계절이... 언제였지?","JPN":"そういえば、イチゴの旬って……いつだっけ？","ENG":"Come to think of it... What season do strawberries grow in...?","TWN":"話說有草莓的季節……是什麼時候？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"꼬마야. 오늘이 몇 월인지 알고 있니?","JPN":"ねえ。今日は何月なのか分かる？","ENG":"Hey, kid. Do you know what month it is?","TWN":"小朋友，你知道今天是幾月嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"몇 월 같은 거 없어. 여긴 낙원이니까.","JPN":"何月とか、そんなのないよ。ここは楽園だから。","ENG":"There's no such thing as months. This is the Promised Land.","TWN":"這裡是樂園，沒有月份這種東西。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"매일매일이 똑같은 날이거든요.","JPN":"毎日毎日、同じ日。","ENG":"Every day is the same day here.","TWN":"因為每天都是一樣的日子。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"날 여기 데려온 사람은 알아? 이 집에 어른이 있니?","JPN":"私をここまで運んできた人を知ってる？　この家に大人はいないの？","ENG":"Do you know who brought me here? Is there an adult in this house?","TWN":"你認識帶我來這裡的人嗎？這房子裡有大人嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"있어요. 벌레 아저씨.","JPN":"いるよ。デレおじさん。","ENG":"Yes. Mr. Belly.","TWN":"有啊，蟲子大叔。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"지금은 정오니까, 기도하는 곳에 있어. 다 같이 모여서 기도하거든요.","JPN":"今はお昼だから、お祈りする所にいるんだ。みんな集まってお祈りするから。","ENG":"It's noon right now, so he's at the place where we pray. We all gather there to pray together.","TWN":"現在是正午，他在禱告的地方。大家會聚在一起祈禱。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"벌레 아저씨...?","JPN":"デレおじさん……？","ENG":"Mr. Belly...?","TWN":"蟲子大叔……？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 사람한테 나 좀 안내 해주겠니?","JPN":"その人のところに案内してくれない？","ENG":"Could you take me to him?","TWN":"可以帶我去找他嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_GIRL","text":{"KOREA":"응!","JPN":"うん！","ENG":"Okay!","TWN":"嗯！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"윽, 햇빛... 눈 부셔.","JPN":"うっ、日差しが……眩しい。","ENG":"Ugh, the sunlight... It's so bright.","TWN":"呃，陽光……好刺眼。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이런 풍경은...","JPN":"こんな景色……","ENG":"I've never seen anything...","TWN":"我這輩子第一次看到……"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"살면서 처음 보는걸.","JPN":"生まれて初めて見た。","ENG":"A view like this in my life.","TWN":"這種景色。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};